---

## **Wiring Table**

| Arduino Pin | Component | Pin Role | Function |
|---|---|---|---|
| D2 | Display | Segment A | (via 220Ω R_A) |
| D3 | Display | Segment B | (via 220Ω R_B) |
| D4 | Display | Segment C | (via 220Ω R_C) |
| D5 | Display | Segment D | (via 220Ω R_D) |
| D6 | Display | Segment E | (via 220Ω R_E) |
| D7 | Display | Segment F | (via 220Ω R_F) |
| D8 | Display | Segment G | (via 220Ω R_G) |
| D12 | Button | Input (pin A) | Button press detection |
| GND | Display + Button | Common Ground | Ground rail |

---

## **Arduino Sketch Code**

```cpp
int counter = 0;
int buttonPin = 12;
int lastButtonState = LOW;

// 7-segment pin mapping (a, b, c, d, e, f, g)
int segmentPins[7] = {2, 3, 4, 5, 6, 7, 8};

void setup() {
  pinMode(buttonPin, INPUT);
  for (int i = 0; i < 7; i++) {
    pinMode(segmentPins[i], OUTPUT);
  }
  displayDigit(0);
}

void loop() {
  int currentButtonState = digitalRead(buttonPin);

  if (currentButtonState == HIGH && lastButtonState == LOW) {
    delay(20);
    if (digitalRead(buttonPin) == HIGH) {
      counter++;
      if (counter > 9) {
        counter = 0;
      }
      displayDigit(counter);
    }
  }

  lastButtonState = currentButtonState;
  delay(10);
}

void displayDigit(int digit) {
  // segment states for digits 0-9
  // order: a, b, c, d, e, f, g
  int a, b, c, d, e, f, g;

  if (digit == 0) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0;
  } else if (digit == 1) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 2) {
    a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1;
  } else if (digit == 3) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1;
  } else if (digit == 4) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1;
  } else if (digit == 5) {
    a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else if (digit == 6) {
    a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 7) {
    a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 8) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 9) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1;
  }

  digitalWrite(segmentPins[0], a);
  digitalWrite(segmentPins[1], b);
  digitalWrite(segmentPins[2], c);
  digitalWrite(segmentPins[3], d);
  digitalWrite(segmentPins[4], e);
  digitalWrite(segmentPins[5], f);
  digitalWrite(segmentPins[6], g);
}
```

